    'T.C. İnkılap Tarihi ve Atatürkçülük': ["1. Ünite: Bir Kahraman Doğuyor - Mustafa Kemal'in çocukluğu, eğitim hayatı, askerlik hayatının başlangıcı.", "2. Ünite: Millî Uyanış: Bağımsızlık Yolunda Atılan Adımlar - I. Dünya Savaşı, Mondros, cemiyetler ve Kuvay-ı Milliye.", "3. Ünite: Millî Bir Destan: Ya İstiklal Ya Ölüm - Kurtuluş Savaşı cepheleri, düzenli ordu, Tekalif-i Milliye.", "4. Ünite: Türkiye Cumhuriyeti'nin Kuruluşu ve İnkılaplar - Cumhuriyetin ilanı, halifeliğin kaldırılması, inkılaplar.", "5. Ünite: Demokratikleşme Çabaları - Çok partili hayata geçiş, suikast girişimi, cumhuriyetin korunması.", "6. Ünite: Atatürk Dönemi Türk Dış Politikası - Lozan, Hatay'ın ana vatana katılması, dış politika ilkeleri.", "7. Ünite: Atatürk'ün Ölümü ve Sonrası - Atatürk'ün vefatı, eserleri, II. Dünya Savaşı süreci ve Türkiye'ye etkileri."],
    'Din Kültürü ve Ahlak Bilgisi': ["1. Ünite: Kader İnancı - Kader/kaza, evrendeki yasalar, irade, tevekkül, Hz. Musa (a.s.) ve Ayet el-Kürsi.", "2. Ünite: Zekât ve Sadaka - Paylaşmanın önemi, zekât/sadaka ibadeti, infak kültürü ve Hz. Şuayb (a.s.).", "3. Ünite: Din ve Sosyal Hayat - Dinin gayesi; can, mal, akıl, nesil ve din emniyeti (temel haklar).", "4. Ünite: Kur'an ve İnsan - Kur'an'ın özellikleri, Hz. Muhammed'in (s.a.v.) örnekliği ve Hz. Lokman'ın öğütleri.", "5. Ünite: Müslümanların Bilim ve Kültüre Katkısı - İslam medeniyetinde bilim, bilim insanları ve kültürel miras."],
    'Beden Eğitimi ve Spor': ["1. Tema: Hareket Yetkinliği - Müsabaka yönetimi, hakemlik işaretleri, strateji geliştirme.", "2. Tema: Aktif ve Sağlıklı Hayat - Kariyer planlama (spor bilimleri), Atatürk'ün spor anlayışı ve sporda liderlik."],
    'Bilişim Teknolojileri ve Yazılım': ["1. Ünite: Bilgi İşlemsel Düşünme ve Programlama - Algoritma, döngüler, koşullar ve değişkenler.", "2. Ünite: Robotik Kodlama ve Sensörler - Arduino ve sensörler (hareket, ışık, mesafe) ile projeler.", "3. Ünite: Dijital Ürün Geliştirme - Blok/metin tabanlı dillerle (Python, Scratch) mobil uygulama/oyun tasarımı.", "4. Ünite: Dijital Okuryazarlık ve Geleceğin Teknolojileri - Yapay zeka, IoT, veri madenciliği ve güvenli internet."],
    'Görsel Sanatlar': ["1. Tema: Hayat ve Sanat - Sanatın günlük yaşamla ilişkisi, sanatsal tasarım süreçleri.", "2. Tema: Sanatın Görsel Dili - Görsel sanat unsurları (çizgi, renk, doku, form) ve tasarım ilkeleri.", "3. Tema: Sanatçılar ve Eserleri - Yerli/milli sanatçılar, Türk ve dünya sanatçıları, sanat akımları.", "4. Tema: Çizim ve Görsel İfade - Karakalem, perspektif çalışmaları, görsel ifade yeteneğini geliştirme.", "5. Tema: Renk ve Estetik - Renk kuramları, renklerin psikolojik etkileri ve estetik düzenlemeler.", "6. Tema: Millî Değerler ve Sanat - Geleneksel Türk sanatları (ebru, tezhip, minyatür) ve kültürel miras.", "7. Tema: Müze ve Kültür - Müze bilinci, sanat eserlerini koruma ve değerlendirme."],
